class IoTClient {
    private val httpClnt = OkHttpClient.Builder()
        .build()

    fun sendRequest(url: String): String? {
        return try {
            var requestBuilder = Request.Builder().url(url)
            if (url.startsWith("http://")) {
                requestBuilder = requestBuilder.get()
            } else {
